/**
 * Handler 1: Token Budget Tracker (per-file, InstructionsLoaded)
 *
 * The real InstructionsLoaded event fires ONCE PER FILE with { file_path,
 * memory_type, load_reason }. This handler accumulates each file's byte size
 * into a session-scoped state file, then warns (once per session, via
 * systemMessage) when the accumulated instruction set crosses the context
 * budget threshold. Silent otherwise — per-file handlers write state files,
 * they never emit additionalContext (output-guard strips it for this event).
 */

import { logHook } from '../lib/common.js';
import { existsSync, readFileSync, statSync } from 'node:fs';
import { basename, join } from 'node:path';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { getSessionTempDir } from '../lib/paths.js';
import type { InstructionsLoadedInput } from '../types.js';
import type { InstructionBudgetState } from './types.js';
import { getContextWindowTokens } from '../lib/context-window.js';

const HOOK_NAME = 'instructions-loaded/token-budget';
const TOKEN_BUDGET_WARN_PCT = 15;

function getStatePath(sessionId: string): string {
  return join(getSessionTempDir(sessionId), 'instruction-budget.json');
}

function loadState(statePath: string): InstructionBudgetState {
  try {
    if (existsSync(statePath)) {
      const parsed = JSON.parse(readFileSync(statePath, 'utf8')) as InstructionBudgetState;
      if (parsed && typeof parsed.files === 'object' && parsed.files !== null) return parsed;
    }
  } catch {
    // Corrupted state — rebuild
  }
  return { version: '1.0', files: {}, warned: false };
}

export function tokenBudgetTracker(input: InstructionsLoadedInput): string | null {
  const statePath = getStatePath(input.session_id);
  const state = loadState(statePath);

  let bytes = 0;
  try {
    bytes = statSync(input.file_path).size;
  } catch {
    // Unreadable file — count as 0 but still record the load
  }
  state.files[input.file_path] = bytes;

  const totalBytes = Object.values(state.files).reduce((sum, b) => sum + b, 0);
  const totalTokens = Math.ceil(totalBytes / 4);
  const fileCount = Object.keys(state.files).length;
  const contextWindow = getContextWindowTokens();
  const pct = (totalTokens / contextWindow) * 100;

  logHook(
    HOOK_NAME,
    `Loaded ${basename(input.file_path)} (${bytes}B); session total ${totalTokens} tokens across ${fileCount} files (${pct.toFixed(1)}% of ${contextWindow})`
  );

  let message: string | null = null;
  if (pct > TOKEN_BUDGET_WARN_PCT && !state.warned) {
    state.warned = true;
    const largest = Object.entries(state.files)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([p, b]) => `${basename(p)} (${Math.ceil(b / 4)})`)
      .join(', ');
    message =
      `[Instruction Budget] Loaded instructions consume >${TOKEN_BUDGET_WARN_PCT}% of context window ` +
      `(${totalTokens} tokens across ${fileCount} files, ${pct.toFixed(1)}%). Largest: ${largest}. ` +
      `Consider trimming or splitting large files.`;
  }

  try {
    atomicWriteSync(statePath, JSON.stringify(state, null, 2));
  } catch (err) {
    logHook(HOOK_NAME, `Failed to save budget state: ${err}`, 'warn');
  }

  return message;
}
